// src/pages/Internship.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import "./Internship.css"; // Optional: for custom styling

export default function Internship() {
  const navigate = useNavigate();
  const currentUser = JSON.parse(localStorage.getItem("currentUser"));
  const role = currentUser?.role;

  const [internships, setInternships] = useState([]);
  const [formData, setFormData] = useState({ title: "", company: "", duration: "" });
  const [editIndex, setEditIndex] = useState(null);
  const [showForm, setShowForm] = useState(false);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(stored);
  }, []);

  useEffect(() => {
    if (role === "Student") {
      toast.error("Access Denied: Students cannot access this page.");
      navigate("/dashboard");
    }
  }, [role, navigate]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleAddOrUpdate = () => {
    if (!formData.title || !formData.company || !formData.duration) {
      toast.warning("Please fill all fields.");
      return;
    }

    const updated = [...internships];
    if (editIndex !== null) {
      updated[editIndex] = formData;
      toast.success("Internship updated!");
    } else {
      updated.push(formData);
      toast.success("Internship added!");
    }

    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
    setFormData({ title: "", company: "", duration: "" });
    setEditIndex(null);
    setShowForm(false);
  };

  const handleEdit = (index) => {
    setFormData(internships[index]);
    setEditIndex(index);
    setShowForm(true);
  };

  const handleDelete = (index) => {
    const updated = internships.filter((_, i) => i !== index);
    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
    toast.info("Internship deleted!");
  };

  return (
    <div className="page">
      <ToastContainer />
      <h2>Internship Management</h2>

      {(role === "Admin" || role === "HR") && (
        <button className="post-btn" onClick={() => setShowForm(true)}>
          + Post Internship
        </button>
      )}

      {showForm && (
        <div className="form-modal">
          <div className="form-box">
            <h3>{editIndex !== null ? "Update Internship" : "Post Internship"}</h3>
            <input name="title" placeholder="Title" value={formData.title} onChange={handleChange} />
            <input name="company" placeholder="Company" value={formData.company} onChange={handleChange} />
            <input name="duration" placeholder="Duration" value={formData.duration} onChange={handleChange} />
            <div className="form-actions">
              <button onClick={handleAddOrUpdate}>
                {editIndex !== null ? "Update" : "Post"}
              </button>
              <button className="cancel-btn" onClick={() => {
                setShowForm(false);
                setFormData({ title: "", company: "", duration: "" });
                setEditIndex(null);
              }}>Cancel</button>
            </div>
          </div>
        </div>
      )}

      <ul className="internship-list">
        {internships.map((intern, index) => (
          <li key={index} className="internship-card">
            <strong>{intern.title}</strong> at <b>{intern.company}</b> ({intern.duration})
            {(role === "Admin" || role === "HR") && (
              <div className="card-actions">
                <button onClick={() => handleEdit(index)}>Edit</button>
                {role === "Admin" && <button onClick={() => handleDelete(index)}>Delete</button>}
              </div>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}
